    /// <summary>
    /// Tries to resolve a material icon token by its canonical string name.
    /// </summary>
    public static bool TryGet(string iconName, out HaloIconToken iconToken)
    {
        if (string.IsNullOrWhiteSpace(iconName))
        {
            iconToken = default;
            return false;
        }

        return Lookup.TryGetValue(iconName.Trim(), out iconToken);
    }
}
